<template>
  <div class="main">
  <el-dialog
        title="提示"
        :visible.sync="dialogVisible"
        width="30%"
        append-to-body
        >
        <div>
            <div class="card_show"> 
                <div class="model_table">
                  <div class="col" v-for='(value , key , index) in data'>
                    <div class="row">{{key}}</div>
                    <div class="row">{{value}}</div>
                  </div>
                </div>
              </div>
        </div>
        <span slot="footer" class="dialog-footer">
            <el-button @click="dialogVisible = false">取 消</el-button>
            <el-button type="primary" @click="dialogVisible = false">确 定</el-button>
        </span>
    </el-dialog>
    <div class="content">
      <Nav index = '4'></Nav>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              北京计量科学院
              </h1>
        <div class="row height100">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">设备分布</h4>
              <div class="card_show">
                <div class="img_map" id ='allmap' style='height:100%'>
            
                </div>
              </div>
            </div>
          </div>

        </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'


export default {
  name: 'Index',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      timer:null,
      marker:[],
      dialogVisible:false,
      data:{
            "医院名称": "",
            "型号规格": "",
            "类型": "",
            "出厂编号": "",
            "生产厂家": "",
            "医院级别": "",
            "等级": "",
            "医院所在区县": "",
            "检定人员": "",
            "数据检定日期": "",
            "证书编号": "",
            "测量条件kv": "",
            "测量条件mA": "",
            "测量条件s": "",
            "测量条件mAs(移动专用）": "",
            "重复性": "",
            "重复性计算结果": "",
            "半值层 铝板厚度mmAL": "",
            "加片后半值层数据": "",
            "线性20mAs？": "",
            "线性数据20mAs": "",
            "线性数据10mAs": "",
            "线性计算结果": ""
        }
    }
  },
  mounted() {
      this.initMap();
      this.initTable()
  },
  methods: {
        initMap(){
            var map = new BMap.Map("allmap");
            var map = new BMap.Map("allmap");
            var point = new BMap.Point(116.404, 39.915);
            map.enableScrollWheelZoom();                            //启用滚轮放大缩小
            map.centerAndZoom(point, 11); 
            map.setMapStyle({style:'midnight'});


            var pointList = [
                {
                    j:116.42,
                    w:39.93
                },
                {
                    j:116.37,
                    w:39.92
                },
                {
                    j:116.22,
                    w:39.9
                },
                {
                    j:116.1,
                    w:39.93
                }
            ]
            for(let i = 0 ; i < pointList.length ; i ++){
                var pt = new BMap.Point(pointList[i].j, pointList[i].w);
                var myIcon = new BMap.Icon("https://s2.ax1x.com/2019/05/14/EohY7t.png", new BMap.Size(70,70));
                this.marker.push(new BMap.Marker(pt,{icon:myIcon}));    // 创建标注
                map.addOverlay(this.marker[i]);                             // 将标注添加到地图中
                this.marker[i].addEventListener('click' , ()=>{
                    this.dialogVisible = true;
                })
            }
        },
        initTable(){
            var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
            this.data = this.gloData[index];
        },
    
  },
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



